import { Server } from "balda"; import OpenAI from "openai"; const server = new Server({ port: 3000 }); const openai = new OpenAI(); async function* streamChatCompletion(messages: any[]) { const stream = await openai.chat.completions.create({ model: "gpt-4", messages, stream: true, }); for await (const chunk of stream) { const content = chunk.choices[0]?.delta?.content; if (content) { yield `data: ${JSON.stringify({ content })}

`; } } yield "data: [DONE]

"; } server.router.post("/chat", async (req, res) => { const { messages } = req.body; res.stream(streamChatCompletion(messages)); });

